import calendar
import datetime as _dt


def add_one_month(d):
    year = d.year + (1 if d.month == 12 else 0)
    month = 1 if d.month == 12 else d.month + 1
    day = min(d.day, calendar.monthrange(year, month)[1])

    if not isinstance(d, _dt.datetime):
        return d.replace(year=year, month=month, day=day)

    if d.tzinfo is None or d.utcoffset() is None:
        return d.replace(year=year, month=month, day=day)

    tz = d.tzinfo

    def wall_key(x):
        return (x.year, x.month, x.day, x.hour, x.minute, x.second, x.microsecond)

    def round_trips(x):
        return wall_key(x.astimezone(_dt.timezone.utc).astimezone(tz)) == wall_key(x)

    candidate_fold_0 = d.replace(year=year, month=month, day=day, fold=0)
    candidate_fold_1 = candidate_fold_0.replace(fold=1)

    valid_0 = round_trips(candidate_fold_0)
    valid_1 = round_trips(candidate_fold_1)

    offset_0 = candidate_fold_0.utcoffset()
    offset_1 = candidate_fold_1.utcoffset()

    if valid_0 and valid_1:
        if offset_0 != offset_1:
            return candidate_fold_1 if d.fold else candidate_fold_0
        return candidate_fold_0

    if valid_0:
        return candidate_fold_0

    if valid_1:
        return candidate_fold_1

    if offset_0 is not None and offset_1 is not None:
        gap = offset_1 - offset_0
        if gap > _dt.timedelta(0):
            adjusted = (candidate_fold_0 + gap).replace(fold=0)
            if round_trips(adjusted):
                return adjusted

    adjusted = candidate_fold_0
    for _ in range(2880):
        adjusted = (adjusted + _dt.timedelta(minutes=1)).replace(fold=0)
        if round_trips(adjusted):
            return adjusted

    return candidate_fold_0
