from datetime import date, datetime, timezone


def add_years(d, n):
    if not isinstance(d, date):
        raise TypeError("d must be a datetime.date")
    if not isinstance(n, int):
        raise TypeError("n must be an integer")

    target_year = d.year + n

    try:
        result = d.replace(year=target_year)
    except ValueError:
        if d.month == 2 and d.day == 29:
            result = d.replace(year=target_year, day=28)
        else:
            raise

    if not isinstance(result, datetime):
        return result

    if result.tzinfo is None or result.utcoffset() is None:
        return result

    tz = result.tzinfo

    def valid_local(dt):
        round_tripped = dt.astimezone(timezone.utc).astimezone(tz)
        return round_tripped.replace(tzinfo=None) == dt.replace(tzinfo=None)

    result_fold0 = result.replace(fold=0)
    result_fold1 = result.replace(fold=1)

    valid_fold0 = valid_local(result_fold0)
    valid_fold1 = valid_local(result_fold1)

    if valid_fold0 or valid_fold1:
        if valid_fold0 and valid_fold1 and result_fold0.utcoffset() != result_fold1.utcoffset():
            return result.replace(fold=getattr(d, "fold", 0))
        return result.replace(fold=0)

    round_tripped = result_fold0.astimezone(timezone.utc).astimezone(tz)
    gap = round_tripped.replace(tzinfo=None) - result_fold0.replace(tzinfo=None)
    resolved_naive = result_fold0.replace(tzinfo=None) + gap
    return resolved_naive.replace(tzinfo=tz, fold=0)
